function LoadData(){$.ajax({url:"data/mydata.json",dataType:"text",success:function(e){var a=$.parseJSON(e);console.log(a),InitTree(a)}}).fail(function(){console.log("An error has occurred.")})}function InitTree(e){(oTree=$("#mytree").jstree({core:{multiple:!1,animation:200,themes:{theme:"default-dark",stripes:!1},data:e},plugins:["search"],search:{case_sensitive:!1,show_only_matches:!1}})).on("dblclick.jstree",function(e,a){var t=$("#mytree").jstree(!0).get_node(e.target);if(console.log(t),t.state.disabled,t.data&&(t.data.length>0||"object"==$.type(t.data))){if(console.log("NODE",t),"object"==$.type(t.data))var r=t.data.file;else var r=t.data;if("http://"==r.substr(0,7)||"https://"==r.substr(0,8))return window.open(r),null;switch(cExt=r.substr(r.lastIndexOf(".")+1),console.log("ext",cExt),cExt){case"html":case"htm":LoadFrame(r+="?"+new Date().getMilliseconds(),"data/");break;case"pdf":LoadFrame(r,"data/")}}else $("#mybody").html("")})}function LoadFrame(e,a){a="string"==typeof a?a:"",console.log(a+e);var t='<iframe class="myiframe" src="'+a+e+'" ></iframe>';$("#mybody").addClass("es_pdf"),$("#mybody").html(t)}function TreeSearch(e){if("string"==typeof e)var a=e;else var a=$("#tree_search").val();console.log("TreeSearch",a),$("#mytree").jstree(!0).search(a)}$(document).ready(function(){console.log("ready..."),LoadData(),$("#tree_search").change(TreeSearch)});